interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => {
    const base = step.items.reduce((sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0), 0);
    return { premium: base * 1.1 + 5 };
  });
  return { results };
};

