const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const FIRST_INSURANCE_SURCHARGE = 1.1;
const PROCESSING_FEE = 5;

// Base premium for `count` alike components: each complete block of 3
// costs COMPONENT_BLOCK_PREMIUM, leftovers cost COMPONENT_PREMIUM each.
const componentGroupPremium = (count: number): number => {
  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
