interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const FIRST_INSURANCE_SURCHARGE = 1.1;
const PROCESSING_FEE = 5;

// Base premium for `count` alike components: a group of exactly 3 forms a
// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
// COMPONENT_PREMIUM.
const componentGroupPremium = (count: number): number =>
  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const sum = (values: number[]): number => values.reduce((acc, value) => acc + value, 0);

// Count how many alike components of each type appear (e.g. { rune: 2 }).
const countByType = (items: Item[]): Map<string, number> =>
  items.reduce((counts, item) => {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    return counts;
  }, new Map<string, number>());

const mainItemsPremium = (items: Item[]): number =>
  sum(items.filter((item) => !isComponent(item)).map((item) => BASE_PREMIUM[item.type] ?? 0));

const componentsPremium = (items: Item[]): number =>
  sum([...countByType(items.filter(isComponent)).values()].map(componentGroupPremium));

const basePremium = (items: Item[]): number =>
  mainItemsPremium(items) + componentsPremium(items);

// Round up to a whole number in MHPCO's favour, guarding against
// floating-point noise (e.g. 197.5000000001) before the ceiling by snapping
// to 6 decimal places first.
const FLOAT_GUARD_PRECISION = 1e6;
const roundUpToWhole = (value: number): number =>
  Math.ceil(Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION);

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => {
    const base = basePremium(step.items);
    const premium = base * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
    return { premium: roundUpToWhole(premium) };
  });
  return { results };
};

