import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Base premiums: single main items (with fee, newcomer first insurance) ---
  // These exercise the simplest quote path. A newcomer (0 years) with one item:
  // base + 10% first insurance, +5 fee.

  // --- Premium: empty / fee only ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // --- Base premiums of main items (isolated base premium via base-premium helper expectations) ---
  it("sword base premium is 100 G (newcomer single sword → 100*1.1 + 5 = 115)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("amulet base premium is 60 G (newcomer single amulet → 60*1.1 + 5 = 71)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("staff base premium is 80 G (newcomer single staff → 80*1.1 + 5 = 93)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("potion base premium is 40 G (newcomer single potion → 40*1.1 + 5 = 49)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });

  // --- Components base premiums ---
  it("one rune base premium is 25 G (newcomer single rune → ceil(25*1.1 + 5) = 33)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 33 });
  });
  it("2 runes → 50 G base premium (newcomer → ceil(50*1.1 + 5) = 60)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes → 60 G base premium (block applies) (newcomer → ceil(60*1.1 + 5) = 71)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("4 runes → 100 G base premium (no block — block requires exactly 3) (newcomer → 115)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("7 runes → 175 G base premium (newcomer → ceil(175*1.1 + 5) = 198)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: Array.from({ length: 7 }, () => ({ type: "rune" })) }],
    });
    expect(result.results[0]).toEqual({ premium: 198 });
  });

  // --- "Alike" components ---
  it("2 runes + 1 moonstone → 75 G base premium (no block: different types) (newcomer → 88)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 88 });
  });
  it("3 runes + 3 moonstones → 120 G base premium (two separate blocks) (newcomer → 137)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 137 });
  });

  // --- Item-specific modifiers in isolation (cursed / high enchantment) ---
  it("cursed item adds 50% surcharge on affected item base (newcomer cursed sword → 100+50+10 +5 = 165)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 165 });
  });
  it.todo("highly enchanted item (enchantment >= 5) adds 30% surcharge on affected item base premium");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("sword with exactly enchantment 5 and cursed → both surcharges apply");

  // --- Policy-wide modifiers ---
  it.todo("customer with exactly 2 years → 20% loyalty discount applies (policy-wide)");
  it.todo("customer with 1 year → no loyalty discount");
  it.todo("first insurance carries a 10% surcharge per item");
  it.todo("each contract after the first quote gets a 15% follow-up discount (policy-wide)");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword (100) + plain amulet (60) → base 160, +50 curse (50% of cursed item) → 210 before fee/policy modifiers");
  it.todo("item-specific modifiers apply to affected item; policy-wide to policy base; fee last");

  // --- Rounding ---
  it.todo("premium yielding 197.5 G → 198 G (rounded up, MHPCO's favor)");

  // --- Integration examples (premium) ---
  it.todo("newcomer cursed sword (0 yrs, steel, ench 3) → premium 165 G");
  it.todo("long-standing customer's second contract (3 yrs, cursed sword steel ench 7) → premium 160 G");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("damage to a rune (value 250), damage 200 → payout 100 (full minus 100 deductible, no special clause)");

  // --- Claim: enchantment threshold ---
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon full reimburse then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
  it.todo("dragon-material sword, exactly ench 8, damage 1000 → payout 400 (high-enchantment clause then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");

  // --- Claim: multiple items of same type ---
  it.todo("policy with two swords → insurance sum 2000, cap 4000");
  it.todo("two sword damage entries → each treated as separate damage with own deductible");
  it.todo("more damage entries of a type than policy covers → claim rejected (throws/non-zero)");

  // --- Claim: cap and insurance sum ---
  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword → cap 2000 based on unmodified insurance value (modifiers do not raise cap)");
  it.todo("policy with sword + 3 runes (block) → insurance sum 1750 (block discount does not affect sum)");
  it.todo("sword (cap 2000), two successive 1500 claims → first payout 1400 (cap remaining 600)");
  it.todo("sword (cap 2000), second 1500 claim → payout 600 (reduced to remaining cap), remaining 0");

  // --- Claim: error cases ---
  it.todo("claim references damage for item not in policy → rejected");
  it.todo("claim with damage amount -200 → rejected");

  // --- Quote: error cases ---
  it.todo("quote includes unknown item type (broomstick) → rejected");

  // --- Multi-step scenario / CLI shape ---
  it.todo("scenario with a quote then a claim returns results array of matching length and order");
});

