// Long-standing customers (>= 2 years) receive 20% off the policy base.
const loyaltyDiscount = (items: Item[], yearsWithMHPCO: number): number =>
  yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE * basePremium(items) : 0;

// Premium for one quote: base premium plus the first-insurance surcharge,
// item-specific curse/enchantment surcharges, less the loyalty discount,
// and the flat processing fee.
const quotePremium = (items: Item[], yearsWithMHPCO: number): number =>
  basePremium(items) * FIRST_INSURANCE_SURCHARGE +
  curseSurcharge(items) +
  enchantmentSurcharge(items) -
  loyaltyDiscount(items, yearsWithMHPCO) +
  PROCESSING_FEE;

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const { yearsWithMHPCO } = scenario.customer;
  const results = scenario.steps.map((step) => ({
    premium: roundUpToWhole(quotePremium(step.items, yearsWithMHPCO)),
  }));
  return { results };
};

