const roundUpToWhole = (value: number): number =>
  Math.ceil(Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION);

// Premium for one quote: base premium plus the first-insurance surcharge,
// item-specific curse/enchantment surcharges, and the flat processing fee.
const quotePremium = (items: Item[]): number =>
  basePremium(items) * FIRST_INSURANCE_SURCHARGE +
  curseSurcharge(items) +
  enchantmentSurcharge(items) +
  PROCESSING_FEE;

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => ({
    premium: roundUpToWhole(quotePremium(step.items)),
  }));
  return { results };
};

