// item-specific curse/enchantment surcharges, less the loyalty discount,
// and the flat processing fee.
const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
  const base = basePremium(items);
  return (
    base * FIRST_INSURANCE_SURCHARGE +
    curseSurcharge(items) +
    enchantmentSurcharge(items) -
    loyaltyDiscount(base, yearsWithMHPCO) +
    PROCESSING_FEE
  );
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const { yearsWithMHPCO } = scenario.customer;
  const results = scenario.steps.map((step) => ({
    premium: roundUpToWhole(quotePremium(step.items, yearsWithMHPCO)),
