// Payout for one damage event: full reimbursement less the per-event deductible.
const damagePayout = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);

// Result of claiming against a policy: total payout (capped) and remaining cap.
const claimResult = (policy: Item[], incident: Incident): { payout: number; remainingCap: number } => {
  const cap = CAP_MULTIPLIER * sum(policy.map(insuranceValue));
  const payout = roundDownToWhole(sum(incident.damages.map(damagePayout)));
  return { payout, remainingCap: cap - payout };
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const { yearsWithMHPCO } = scenario.customer;
  const policies: Item[][] = [];
  let quotesSeen = 0;
  const results = scenario.steps.map((step) => {
    if (step.op === "claim") {
      return claimResult(policies[step.policy], step.incident);
    }
    const isFollowUp = quotesSeen > 0;
    quotesSeen += 1;
    policies.push(step.items);
    return { premium: roundUpToWhole(quotePremium(step.items, yearsWithMHPCO, isFollowUp)) };
  });
  return { results };
};

